const IMAGE_SRC =
    "data:image/webp;base64,";

const img = new Image();
img.src = IMAGE_SRC;

let canvas, ctx;
const declineRate = 1;
const initialOpacity = 0.7;
const fogRange = 100;

const stars = []; // {x, y, opacity, size}

function ok(x, y, size, w, h) {
    const xDist = Math.min(x, w - x);
    const yDist = Math.min(y, h - y);
    return xDist >= size / 2 && yDist >= size / 2;
}

function makeStar() {
    const size = 30 + Math.random() * 2;
    const dist = Math.random();
    const falloff = Math.exp(-dist * declineRate);
    const opacity = Math.max(0, initialOpacity * falloff);
    const appearentSize = Math.max(0, size * falloff);

    const rotate = Math.random() * Math.PI;

    do {
        x = Math.random() * canvas.width;
        y = Math.random() * canvas.height;
    } while (!ok(x, y, appearentSize, canvas.width, canvas.height));

    stars.push({ x, y, opacity, size: appearentSize, depth: dist, rotate });
}

function fog(y, opacity) {
    const distY = Math.min(y, canvas.height - y);
    if (distY < 0) return 0;
    return Math.min((opacity * distY) / fogRange, opacity);
}

function drawStars(scrollY = 0) {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    for (const s of stars) {
        const offsetY = scrollY * s.depth * 0.8 + 1;

        ctx.save();
        ctx.globalAlpha = fog(s.y + offsetY, s.opacity);
        ctx.translate(s.x, s.y + offsetY);
        ctx.rotate(s.rotate);
        ctx.drawImage(img, -s.size / 2, -s.size / 2, s.size, s.size);
        ctx.restore();
    }
}

document.addEventListener("DOMContentLoaded", () => {
    canvas = document.querySelector("#ui-hero-canvas");
    ctx = canvas.getContext("2d");

    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;

    for (let i = 0; i < 64; i++) {
        makeStar();
    }
    img.onload = () => {
        drawStars();
    };

    if (img.complete) {
        drawStars();
    }
});

window.addEventListener("scroll", () => {
    drawStars(window.scrollY);
});

window.addEventListener("resize", () => {
    if (!canvas) return;

    const prevWidth = canvas.width;
    const prevHeight = canvas.height;

    const newWidth = canvas.offsetWidth;
    const newHeight = canvas.offsetHeight;

    for (const s of stars) {
        s.x *= newWidth / prevWidth;
        s.y *= newHeight / prevHeight;
    }

    canvas.width = newWidth;
    canvas.height = newHeight;

    drawStars(window.scrollY);
});
